INSERT INTO `announcement` (`id`, `title`, `content`, `type`, `pinned`, `scope`, `room_id`, `publisher_id`, `status`, `published_at`, `view_count`, `created_at`, `updated_at`) VALUES
(1,'暑期自习室开放安排','暑假期间图书馆总馆信息楼三楼自修室开放时间调整为 08:00-22:00，请同学们按需预约。','系统通知',1,'全局',NULL,1,'已发布','2025-06-01 08:30:00',1260,'2025-06-01 08:30:00','2025-06-01 08:30:00'),
(2,'新学期预约规则提醒','新学期开始后，预约开始前后 15 分钟内可由管理员按学号签到，超时未签到将扣除信用分。','使用规则',1,'全局',NULL,1,'已发布','2025-09-01 09:00:00',2210,'2025-09-01 09:00:00','2025-09-01 09:00:00'),
(3,'期中周座位使用提醒','期中复习周预约需求较高，请同学们按时签到，离开时主动签退。','使用规则',0,'全局',NULL,3,'已发布','2025-11-10 10:00:00',1498,'2025-11-10 10:00:00','2025-11-10 10:00:00'),
(4,'期末周延长开放通知','期末周图书馆总馆自修室开放至 23:30，启林南分馆开放至 23:00。','系统通知',1,'全局',NULL,2,'已发布','2026-01-05 08:20:00',3521,'2026-01-05 08:20:00','2026-01-05 08:20:00'),
(5,'春季学期座位维护公告','主楼二楼部分靠窗座位将分批维护，维护期间请选择其他座位。','维护公告',0,'自习室',2,3,'已发布','2026-03-03 09:15:00',880,'2026-03-03 09:15:00','2026-03-03 09:15:00'),
(6,'毕业季文明自习倡议','请毕业班同学离馆时带走个人物品，共同维护自习环境。','系统通知',0,'全局',NULL,1,'已发布','2026-05-20 08:30:00',642,'2026-05-20 08:30:00','2026-05-20 08:30:00');
